        // Instance normalization (per batch element)
        val = (val - batch_mean) * inv_std;

        // Add residual (y) and multiply by y
        T y_val = y[batch_idx * out_features + f];
        val = (val + y_val) * y_val;

        output[batch_idx * out_features + f] = val;
    }
