#include <torch/extension.h>
#include <cuda_runtime.h>
#include <math.h>

template<typename T>
__global__ void fused_bmm_norm_residual_mul_kernel(
    const T* x,           // [batch_size, in_features]
    const T* weight,      // [out_features, in_features]
    const T* bias,        // [out_features]
    const T* y,           // [batch_size, out_features]
    T* running_mean,      // [out_features]
    T* running_var,       // [out_features]
    T* output,            // [batch_size, out_features]
    int batch_size,
    int in_features,
    int out_features,
    T eps,
    T momentum,
    bool training
) {
    // Each thread block processes one batch element
    int batch_idx = blockIdx.x;
    if (batch_idx >= batch_size) return;

    int tid = threadIdx.x;
    int feature_idx = tid;

    // Shared memory for statistics
    __shared__ T shared_mean;
    __shared__ T shared_var;

    const T* x_row = &x[batch_idx * in_features];

    // Compute mean for this batch element across features
    T mean = 0;
    for (int f = feature_idx; f < out_features; f += blockDim.x) {
        // Compute BMM: x[batch_idx] * weight[f]
        T val = bias[f];
        const T* w_row = &weight[f * in_features];

        for (int j = 0; j < in_features; j++) {
            val += x_row[j] * w_row[j];
        }
        mean += val;
    }

    // Reduce mean across threads in block
    __shared__ T mean_reduce[255];
    mean_reduce[tid] = mean;
    __syncthreads();

    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            mean_reduce[tid] += mean_reduce[tid + stride];
        }
        __syncthreads();
    }

    if (tid == 0) {
        shared_mean = mean_reduce[0] / static_cast<T>(out_features);
    }
    __syncthreads();

    T batch_mean = shared_mean;

    // Compute variance for this batch element
    T var = 0;
    for (int f = feature_idx; f < out_features; f += blockDim.x) {
        T val = bias[f];
        const T* w_row = &weight[f * in_features];

        for (int j = 0; j < in_features; j++) {
            val += x_row[j] * w_row[j];
        }
        T diff = val - batch_mean;
        var += diff * diff;
    }

    // Reduce variance across threads
    __shared__ T var_reduce[256];
    var_reduce[tid] = var;
    __syncthreads();

    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            var_reduce[tid] += var_reduce[tid + stride];
        }
        __syncthreads();
    }

