    __syncthreads();

    T batch_var = shared_var;
    T inv_std = static_cast<T>(1) / sqrt(batch_var + eps);

    // Normalize, add residual, and multiply
    for (int f = feature_idx; f < out_features; f += blockDim.x) {
        // Compute BMM
        T val = bias[f];
        const T* w_row = &weight[f * in_features];

        for (int j = 0; j < in_features; j++) {
            val += x_row[j] * w_row[j];
        }

        // Instance normalization (per batch element)
        val = (val - batch_mean) * inv_std;

        // Add residual (y) and multiply by y
        T y_val = y[batch_idx * out_features + f];
        val = (val + y_val) * y_val;

        output[batch_idx * out_features + f] = val;
    }
