        self.running_mean.zero_()
        self.running_var.fill_(1)

    def forward(self, x, y):
        return fused_operation.fused_operation_cuda(
            x,
            self.weight,
            self.bias,
            y,
            self.running_mean,
            self.running_var,
            self.eps,
            self.momentum,
            self.training
        )

import torch
import torch.nn as nn
import math
from torch.utils.cpp_extension import load_inline

# Define fused CUDA kernel for BMM + InstanceNorm + Residual + Multiplication
fused_operation_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <math.h>

template<typename T>
__global__ void fused_bmm_norm_residual_mul_kernel(
    const T* x,           // [batch_size, in_features]
    const T* weight,      // [out_features, in_features]
    const T* bias,        // [out_features]
    const T* y,           // [batch_size, out_features]
    T* running_mean,      // [out_features]
    T* running_var,       // [out_features]
    T* output,            // [batch_size, out_features]
    int batch_size,
    int in_features,
    int out_features,
    T eps,
    T momentum,
    bool training
) {
    // Each thread block processes one batch element
    int batch_idx = blockIdx.x;
    if (batch_idx >= batch_size) return;

    int tid = threadIdx.x;
    int feature_idx = tid;

    // Shared memory for statistics
    __shared__ T shared_mean;
    __shared__ T shared_var;

    const T* x_row = &x[batch_idx * in_features];

    // Compute mean for this batch element across features
    T mean = 0;
    for (int f = feature_idx; f < out_features; f += blockDim.x) {
        // Compute BMM: x[batch_idx] * weight[f]
        T val = bias[f];
        const T* w_row = &weight[f * in_features];

        for (int j = 0; j < in_features; j++) {
            val += x_row[j] * w_row[j];
        }
        mean += val;
    }

    // Reduce mean across threads in block
    __shared__ T mean_reduce[256];
    mean_reduce[tid] = mean;
    __syncthreads();

    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            mean_reduce[tid] += mean_reduce[tid + stride];
        }
        __syncthreads();
    }

    if (tid == 0) {
        shared_mean = mean_reduce[0] / static_cast<T>(out_features);
    }
    __syncthreads();

    T batch_mean = shared_mean;

    // Compute variance for this batch element
    T var = 0;
    for (int f = feature_idx; f < out_features; f += blockDim.x) {
        T val = bias[f];
        const T* w_row = &weight[f * in_features];

        for (int j = 0; j < in_features; j++) {
            val += x_row[j] * w_row[j];
        }
        T diff = val - batch_mean;
        var += diff * diff;
    }

    // Reduce variance across threads
    __shared__ T var_reduce[256];
    var_reduce[tid] = var;
    __syncthreads();

    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            var_reduce[tid] += var_reduce[tid + stride];
        }
        __syncthreads();
    }

    if (tid == 0) {
        shared_var = var_reduce[0] / static_cast<T>(out_features);

        // Update running statistics if training
        if (training) {
            atomicAdd(&running_mean[0], momentum * (batch_mean - running_mean[0]));
            atomicAdd(&running_var[0], momentum * (shared_var - running_var[0]));
        }
    }
    __syncthreads();

    T batch_var = shared_var;
    T inv_std = static_cast<T>(1) / sqrt(batch_var + eps);

    // Normalize, add residual, and multiply
    for (int f = feature_idx; f < out_features; f += blockDim.x) {
        // Compute BMM
        T val = bias[f];
        const T* w_row = &weight[f * in_features];

        for (int j = 0; j < in_features; j++) {
            val += x_row[j] * w_row[j];
        }

        // Instance normalization (per batch element)
        val = (val - batch_mean) * inv_std;

        // Add residual (y) and multiply by y
        T y_val = y[batch_idx * out_features + f];
        val = (val + y_val) * y_val;

        output[batch_idx * out_features + f] = val;
    }
}

torch::Tensor fused_operation_cuda(
    torch::Tensor x,
    torch::Tensor weight,
    torch::Tensor bias,
    torch::Tensor y,
    torch::Tensor running_mean,
    torch::Tensor running_var,
    float eps,
    float momentum,
    bool training
) {
    auto batch_size = x.size(0);
    auto in_features = x.size(1);
    auto out_features = weight.size(0);

    auto output = torch::empty({batch_size, out_features}, x.options());

    const int threads_per_block = 256;
    const int num_blocks = batch_size;

    AT_DISPATCH_FLOATING_TYPES(x.scalar_type(), "fused_operation_cuda", ([&] {
        fused_bmm_norm_residual_mul_kernel<scalar_t><<<num_blocks, threads_per_block>>>(
            x.data_ptr<scalar_t>(),
            weight.data_ptr<scalar_t>(),
            bias.data_ptr<scalar_t>(),
            y.data_ptr<scalar_t>(),
            running_mean.data_ptr<scalar_t>(),
            running_var.data_ptr<scalar_t>(),
            output.data_ptr<scalar_t>(),
            batch_size,
            in_features,
            out_features,
            static_cast<scalar_t>(eps),
            static_cast<scalar_t>(momentum),
            training
        );
    }));

    cudaDeviceSynchronize();
    return output;
}
"""

fused_operation_cpp_source = """
torch::Tensor fused_operation_cuda(
    torch::Tensor x,
    torch::Tensor weight,
    torch::Tensor bias,
    torch::Tensor y,
    torch::Tensor running_mean,
    torch::Tensor running_var,
    float eps,
    float momentum,
    bool training
);
"""

# Compile the inline CUDA code
fused_operation = load_inline(
    name="fused_operation",
    cpp_sources=fused_operation_cpp_source,
    cuda_sources=fused_operation_source,
    functions=["fused_operation_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=[""],
)

class ModelNew(nn.Module):
    def __init__(self, in_features, out_features, eps=1e-5, momentum=0.1):
        super(ModelNew, self).__init__()
        self.in_features = in_features
        self.out_features = out_features
        self.eps = eps
        self.momentum = momentum

        # Linear layer parameters
        self.weight = nn.Parameter(torch.Tensor(out_features, in_features))
        self.bias = nn.Parameter(torch.Tensor(out_features))

        # InstanceNorm statistics (single value for global statistics)
        self.register_buffer('running_mean', torch.zeros(1))
        self.register_buffer('running_var', torch.ones(1))

        # Initialize parameters
        self.reset_parameters()

    def reset_parameters(self):
        nn.init.kaiming_uniform_(self.weight, a=math.sqrt(5))
        if self.bias is not None:
            fan_in, _ = nn.init._calculate_fan_in_and_fan_out(self.weight)
            bound = math.sqrt(fan_in) if fan_in > 0 else 0
            nn.init.uniform_(self.bias, -bound, bound)

        self.running_mean.zero_()
        self.running_var.fill_(1)

    def forward(self, x, y):
        return fused_operation.fused_operation_cuda(
            x,
            self.weight,
            self.bias,
            y,
            self.running_mean,
            self.running_var,
            self.eps,
            self.momentum,
            self.training
        )
